import { CommonModule } from '@angular/common';
import { Component, inject, Injectable, OnDestroy, OnInit, signal } from '@angular/core';
import { TranslateModule } from '@ngx-translate/core';
import { FNIconComponent } from '@arpudhabotupload/fn-icon-angular';
import { BehaviorSubject, Subscription } from 'rxjs';

export interface Toast {
  id: string;
  type: 'success' | 'error' | 'warn' | 'info';
  title?: string;
  message: string;
  duration?: number;
  isVisible?: boolean;
}

@Injectable({
  providedIn: 'root',
})
export class ToastService {
  private readonly toastsSubject = new BehaviorSubject<Toast[]>([]);
  public toasts$ = this.toastsSubject.asObservable();

  private generateId(): string {
    return crypto.randomUUID();
  }

  private addToast(toast: Omit<Toast, 'id'>) {
    const newToast: Toast = {
      ...toast,
      id: this.generateId(),
      isVisible: false,
    };

    const currentToasts = this.toastsSubject.value;
    this.toastsSubject.next([...currentToasts, newToast]);

    // Trigger animation
    setTimeout(() => {
      const toasts = this.toastsSubject.value;
      const toastIndex = toasts.findIndex((t) => t.id === newToast.id);
      if (toastIndex !== -1) {
        toasts[toastIndex].isVisible = true;
        this.toastsSubject.next([...toasts]);
      }
    }, 10);

    // Auto remove if duration is specified
    if (toast.duration && toast.duration > 0) {
      setTimeout(() => {
        this.remove(newToast.id);
      }, toast.duration);
    }

    return newToast.id;
  }

  success(message: string, title?: string, duration = 3000): string {
    return this.addToast({
      type: 'success',
      title,
      message,
      duration,
    });
  }

  error(message: string, title?: string, duration = 5000): string {
    return this.addToast({
      type: 'error',
      title,
      message,
      duration,
    });
  }

  warn(message: string, title?: string, duration = 5000): string {
    return this.addToast({
      type: 'warn',
      title,
      message,
      duration,
    });
  }

  info(message: string, title?: string, duration = 5000): string {
    return this.addToast({
      type: 'info',
      title,
      message,
      duration,
    });
  }

  remove(id: string) {
    const currentToasts = this.toastsSubject.value;
    const filteredToasts = currentToasts.filter((toast) => toast.id !== id);
    this.toastsSubject.next(filteredToasts);
  }

  clear() {
    this.toastsSubject.next([]);
  }
}

@Component({
  selector: 'fn-toast',
  templateUrl: './fn-toast.component.html',
  styleUrls: ['./fn-toast.component.scss'],
  standalone: true,
  imports: [CommonModule, FNIconComponent, TranslateModule],
})
export class FNToast implements OnInit, OnDestroy {
  toasts = signal<Toast[]>([]);
  private readonly subscription: Subscription = new Subscription();
  private readonly toastService = inject(ToastService);

  constructor() {}

  ngOnInit() {
    this.subscription.add(
      this.toastService.toasts$.subscribe((toasts) => {
        this.toasts.set(toasts);
      }),
    );
  }

  ngOnDestroy() {
    this.subscription.unsubscribe();
  }

  removeToast(id: string) {
    this.toastService.remove(id);
  }

  getIconName(toast: Toast): string {
    switch (toast.type) {
      case 'success':
        return 'check-circle-colour';
      case 'warn':
        return 'info-circle-colour';
      case 'error':
        return 'exclamation-circle-colour';
      case 'info':
        return 'info-circle-colour';
      default:
        return 'info-circle-colour';
    }
  }
}
